mapper.select:
SELECT o.id AS orderId, t.id AS taskId, t.title AS taskTitle, AS taskCategory, t.location AS taskLocation, t.reward, AS status, poster.id AS posterId, poster.nickname AS posterName, poster.avatar_url AS posterAvatarUrl, helper.id AS helperId, helper.nickname AS helperName, helper.avatar_url AS helperAvatarUrl, o.create_time AS createdAt, o.update_time AS updatedAt FROM t_order o JOIN t_task t ON t.id = o.task_id AND t.is_deleted = false JOIN u_user poster ON poster.id = o.poster_id AND poster.is_deleted = false JOIN u_user helper ON helper.id = o.helper_id AND helper.is_deleted = false WHERE o.is_deleted = false AND ( (#{role} = 'poster' AND o.poster_id = #{userId}) OR (#{role} = 'helper' AND o.helper_id = #{userId}) OR (#{role} IS NULL AND (o.poster_id = #{userId} OR o.helper_id = #{userId})) )
AND o.status = #{status}
ORDER BY o.create_time DESC OFFSET #{offset} LIMIT #{size}

mapper.update:
UPDATE t_order
SET status = #{newStatus},
    version = version + 1,
    update_time = CURRENT_TIMESTAMP
WHERE id = #{orderId}
  AND is_deleted = false
  AND status = #{currentStatus}
  AND version = #{expectedVersion}
